import { LIMEZU_ASSET_CLASSIFICATION } from "./AssetClassification";
import { LIMEZU_ASSET_METADATA } from "./AssetMetadata";

const DRAFT_CLASSIFICATION_STORAGE_KEY = "limezu.assetClassificationDraft.v2";
const DRAFT_CLASSIFICATION_SOURCE_KEY = "limezu.assetClassificationDraftSource.v2";
const DRAFT_METADATA_STORAGE_KEY = "limezu.assetMetadataDraft.v1";

let cachedDraftClassification: LimeZuAssetClassification = {};
let cachedDraftMetadata: LimeZuAssetMetadata = {};

const classificationSource = LIMEZU_ASSET_CLASSIFICATION as Record<string, LimeZuAssetCategory>;
const metadataSource = LIMEZU_ASSET_METADATA as LimeZuAssetMetadata;

function classificationSourceSignature() {
  // Keep this small. Storing JSON.stringify(classificationSource) can exceed
  // localStorage quota and crash the app before React renders.
  const entries = Object.entries(classificationSource).sort(([a], [b]) => a.localeCompare(b));
  let hash = 2166136261;

  for (const [assetId, category] of entries) {
    const text = `${assetId}:${category};`;
    for (let i = 0; i < text.length; i += 1) {
      hash ^= text.charCodeAt(i);
      hash = Math.imul(hash, 16777619);
    }
  }

  return `${entries.length}:${(hash >>> 0).toString(16)}`;
}

function safeLocalStorageGet(key: string) {
  try {
    return window.localStorage.getItem(key);
  } catch {
    return null;
  }
}

function safeLocalStorageSet(key: string, value: string) {
  try {
    window.localStorage.setItem(key, value);
  } catch {
    // Ignore storage quota/security errors. The committed AssetClassification.ts
    // remains the source of truth even if the browser cannot store a cache key.
  }
}

function safeLocalStorageRemove(key: string) {
  try {
    window.localStorage.removeItem(key);
  } catch {
    // Ignore storage errors.
  }
}

function clearStaleDraftIfSourceChanged() {
  if (typeof window === "undefined") return;

  const currentSignature = classificationSourceSignature();
  const storedSignature = safeLocalStorageGet(DRAFT_CLASSIFICATION_SOURCE_KEY);

  if (storedSignature && storedSignature !== currentSignature) {
    safeLocalStorageRemove(DRAFT_CLASSIFICATION_STORAGE_KEY);
    cachedDraftClassification = {};
  }

  safeLocalStorageSet(DRAFT_CLASSIFICATION_SOURCE_KEY, currentSignature);
}

export function defaultAssetClassification(): LimeZuAssetClassification {
  return Object.fromEntries(
    LIMEZU_ASSET_CATALOG.map(asset => [
      asset.id,
      classificationSource[asset.id] ?? asset.defaultCategory,
    ]),
  );
}

export function readDraftAssetClassification(): LimeZuAssetClassification {
  if (typeof window === "undefined") return cachedDraftClassification;

  clearStaleDraftIfSourceChanged();

  try {
    const raw = window.localStorage.getItem(DRAFT_CLASSIFICATION_STORAGE_KEY);
    cachedDraftClassification = raw ? JSON.parse(raw) : {};
  } catch {
    cachedDraftClassification = {};
  }

  return cachedDraftClassification;
}

export function readAssetClassification(): LimeZuAssetClassification {
  return {
    ...defaultAssetClassification(),
    ...readDraftAssetClassification(),
  };
}

export function readDraftAssetMetadata(): LimeZuAssetMetadata {
  if (typeof window === "undefined") return cachedDraftMetadata;

  try {
    const raw = window.localStorage.getItem(DRAFT_METADATA_STORAGE_KEY);
    cachedDraftMetadata = raw ? JSON.parse(raw) : {};
  } catch {
    cachedDraftMetadata = {};
  }

  return cachedDraftMetadata;
}

export function readAssetMetadata(): LimeZuAssetMetadata {
  return {
    ...metadataSource,
    ...readDraftAssetMetadata(),
  };
}

export function writeAssetMetadata(next: LimeZuAssetMetadata) {
  cachedDraftMetadata = Object.fromEntries(
    Object.entries(next).filter(([, metadata]) => metadata.objectWalkable !== undefined || metadata.buildingPlacement !== undefined),
  );

  if (typeof window !== "undefined") {
    safeLocalStorageSet(DRAFT_METADATA_STORAGE_KEY, JSON.stringify(cachedDraftMetadata));
    window.dispatchEvent(new CustomEvent("limezu:asset-metadata-changed"));
  }
}

export function updateAssetMetadata(assetId: string, patch: LimeZuAssetMetadata[string]) {
  const current = readAssetMetadata();

  writeAssetMetadata({
    ...current,
    [assetId]: {
      ...(current[assetId] ?? {}),
      ...patch,
    },
  });
}

export function objectAssetIsWalkable(assetId: string | undefined) {
  if (!assetId) return false;
  return readAssetMetadata()[assetId]?.objectWalkable === true;
}

export function buildingAssetPlacement(assetId: string | undefined) {
  if (!assetId) return "outside";
  return readAssetMetadata()[assetId]?.buildingPlacement ?? "outside";
}

export function writeAssetClassification(next: LimeZuAssetClassification) {
  const defaults = defaultAssetClassification();
  const draft: LimeZuAssetClassification = {};

  for (const [assetId, category] of Object.entries(next)) {
    if (defaults[assetId] !== category) draft[assetId] = category;
  }

  cachedDraftClassification = draft;

  if (typeof window !== "undefined") {
    safeLocalStorageSet(DRAFT_CLASSIFICATION_SOURCE_KEY, classificationSourceSignature());
    safeLocalStorageSet(DRAFT_CLASSIFICATION_STORAGE_KEY, JSON.stringify(cachedDraftClassification));
    window.dispatchEvent(new CustomEvent("limezu:asset-classification-changed"));
  }
}

export function classifyAsset(assetId: string, category: LimeZuAssetCategory) {
  writeAssetClassification({
    ...readAssetClassification(),
    [assetId]: category,
  });
}

export function uncategorizeAsset(assetId: string) {
  classifyAsset(assetId, "uncategorized");
}

export function classifyAssets(assetIds: string[], category: LimeZuAssetCategory) {
  const next = { ...readAssetClassification() };
  for (const id of assetIds) next[id] = category;
  writeAssetClassification(next);
}

export function assetsForCategory(category: LimeZuAssetCategory) {
  const classification = readAssetClassification();
  return LIMEZU_ASSET_CATALOG.filter(asset => (classification[asset.id] ?? asset.defaultCategory) === category);
}

export function getCatalogAsset(id: string | undefined): LimeZuCatalogAsset {
  return LIMEZU_ASSET_CATALOG.find(asset => asset.id === id) ?? LIMEZU_ASSET_CATALOG[0];
}

export function resetDraftAssetClassification() {
  cachedDraftClassification = {};
  cachedDraftMetadata = {};

  if (typeof window !== "undefined") {
    safeLocalStorageRemove(DRAFT_CLASSIFICATION_STORAGE_KEY);
    safeLocalStorageRemove(DRAFT_METADATA_STORAGE_KEY);
    safeLocalStorageSet(DRAFT_CLASSIFICATION_SOURCE_KEY, classificationSourceSignature());
    window.dispatchEvent(new CustomEvent("limezu:asset-classification-changed"));
    window.dispatchEvent(new CustomEvent("limezu:asset-metadata-changed"));
  }
}

export function exportAssetClassificationTs(): string {
  const current = readAssetClassification();
  const ordered = Object.fromEntries(
    LIMEZU_ASSET_CATALOG.map(asset => [asset.id, current[asset.id] ?? asset.defaultCategory]),
  );

  return `import type { LimeZuAssetCategory } from "./AssetCatalog";

/**
 * Global LimeZu asset classification.
 * Generated by the Satiria Asset Manager.
 */
export const LIMEZU_ASSET_CLASSIFICATION = ${JSON.stringify(ordered, null, 2)} as const satisfies Record<string, LimeZuAssetCategory>;
`;
}

export function exportAssetMetadataTs(): string {
  const metadata = readAssetMetadata();
  const ordered = Object.fromEntries(
    LIMEZU_ASSET_CATALOG
      .map(asset => [asset.id, metadata[asset.id]] as const)
      .filter(([, value]) => value && (value.objectWalkable !== undefined || value.buildingPlacement !== undefined)),
  );

  return `import type { LimeZuAssetMetadata } from "./AssetCatalog";

/**
 * Global LimeZu asset metadata.
 * Generated by the Satiria Asset Manager.
 */
export const LIMEZU_ASSET_METADATA = ${JSON.stringify(ordered, null, 2)} as const satisfies LimeZuAssetMetadata;
`;
}

export function assetManagerStats() {
  const classification = readAssetClassification();
  const categories: LimeZuAssetCategory[] = ["uncategorized", "terrain", "object", "building", "character", "npc", "effect", "ui", "ignore"] as LimeZuAssetCategory[];
  const counts = Object.fromEntries(categories.map(category => [category, 0])) as Record<LimeZuAssetCategory, number>;

  for (const asset of LIMEZU_ASSET_CATALOG) {
    const category = classification[asset.id] ?? asset.defaultCategory;
    counts[category] = (counts[category] ?? 0) + 1;
  }

  return { total: LIMEZU_ASSET_CATALOG.length, counts };
}
